def evaluate_expression(expr: str) -> str:
    try:
        # Remove whitespace and validate input
        expr = expr.strip()
        if not expr:
            return ""

        # Only allow safe characters for arithmetic expressions
        allowed_chars = set('0123456789+-*/().e ')
        if not all(c in allowed_chars for c in expr):
            return ""

        # Prevent dangerous operations by checking for forbidden patterns
        forbidden = ['__', 'import', 'exec', 'eval', 'open', 'file', 'input', 'raw_input']
        expr_lower = expr.lower()
        if any(pattern in expr_lower for pattern in forbidden):
            return ""

        # Use eval with restricted globals and locals
        result = eval(expr, {"__builtins__": {}}, {})

        # Ensure result is a number
        if isinstance(result, (int, float, complex)):
            return str(result)
        else:
            return ""

    except:
        return ""

